void allocHostMem(int num, int dim)
{
	coord_h	= (float*) malloc( num * dim * sizeof(float) );
}

void freeHostMem()
{
	free(coord_h);
}

inline float dist(int p1, int p2, int num, int dim, float *coord_h)
{
	float retval = 0.0f;
	for(int i = 0; i < dim; i++){
		float tmp = coord_h[(i*num)+p1] - coord_h[(i*num)+p2];
		retval += tmp * tmp;
	}
	return retval;
}

float dist(Point p1, Point p2, int dim)
{
  float result=0.0;
  for (int i=0;i<dim;i++)
    result += (p1.coord[i] - p2.coord[i])*(p1.coord[i] - p2.coord[i]);
  return(result);
}

float pgain( long x, Points *points, float z, long int *numcenters, int kmax, bool *is_center, int *center_table, bool *switch_membership, bool isCoordChanged,
							double *serial_t, double *cpu_to_gpu_t, double *gpu_to_cpu_t, double *alloc_t, double *kernel_t, double *free_t)
{	
	int stride	= *numcenters + 1;			
	int K		= *numcenters ;				
	int num		=  points->num;				
	int dim		=  points->dim;				
	int nThread =  num;						

	work_mem_h = (float*) malloc(stride * (nThread + 1) * sizeof(float) );

	if(iter == 0)
	{
		allocHostMem(num, dim);
	}

	int count = 0;
	for( int i=0; i<num; i++)
	{
		if( is_center[i] )
		{
			center_table[i] = count++;
		}
	}

	if(isCoordChanged || 0 == iter)
	{
		for(int i=0; i<dim; i++)
		{
			for(int j=0; j<num; j++)
			{
				coord_h[ (num*i)+j ] = points->p[j].coord[i];
			}
		}
	}

	// Allocate device memory equivalents (host arrays here)
	center_table_h = (int*) malloc(num * sizeof(int));
	switch_membership_h = (bool*) malloc(num * sizeof(bool));
	p_h = (Point*) malloc(num * sizeof(Point));

	// Copy data to device arrays (host arrays here)
	memcpy(center_table_h, center_table, num * sizeof(int));
	memcpy(p_h, points->p, num * sizeof(Point));
	memset(switch_membership_h, 0, num * sizeof(bool));
	memset(work_mem_h, 0, stride * (nThread + 1) * sizeof(float));

	// Kernel computation replaced by OpenMP parallel loop
	#pragma omp parallel for schedule(static)
	for(int tid = 0; tid < num; tid++)
	{
		float *lower = &work_mem_h[tid*stride];
		float x_cost = 0.0f;
		// Compute distance squared between tid and x
		for(int i = 0; i < dim; i++){
			float tmp = coord_h[(i*num)+tid] - coord_h[(i*num)+x];
			x_cost += tmp * tmp;
		}
		x_cost *= p_h[tid].weight;

		if ( x_cost < p_h[tid].cost )
		{
			switch_membership_h[tid] = true;
			lower[K] += x_cost - p_h[tid].cost;
		}
		else
		{
			lower[center_table_h[p_h[tid].assign]] += p_h[tid].cost - x_cost;
		}
	}

	int number_of_centers_to_close = 0;
	float gl_cost_of_opening_x = z;
	float *gl_lower = &work_mem_h[stride * nThread];

	for(int i=0; i<num; i++)
	{
		if( is_center[i] )
		{
			float low = z;
		    for( int j = 0; j<num; j++ )
			{
				low += work_mem_h[ j*stride + center_table[i] ];
			}

		    gl_lower[center_table[i]] = low;

		    if ( low > 0 )
			{
				++number_of_centers_to_close;
				work_mem_h[i*stride+K] -= low;
		    }
		}
		gl_cost_of_opening_x += work_mem_h[i*stride+K];
	}

	if ( 0 > gl_cost_of_opening_x )
	{
		for(int i = 0; i<num; i++)
		{
			bool close_center = gl_lower[center_table[points->p[i].assign]] > 0 ;
			if ( switch_membership_h[i] || close_center )
			{
				points->p[i].cost = dist(points->p[i], points->p[x], dim) * points->p[i].weight;
				points->p[i].assign = x;
			}
		}

		for(int i = 0; i<num; i++)
		{
			if( is_center[i] && 0 < gl_lower[center_table[i]] )
			{
				is_center[i] = false;
			}
		}

		if( 0 <= x && x < num)
		{
			is_center[x] = true;
		}
		*numcenters = *numcenters + 1 - number_of_centers_to_close;
	}
	else
	{
		gl_cost_of_opening_x = 0;
	}

	free(work_mem_h);
	free(center_table_h);
	free(switch_membership_h);
	free(p_h);

	iter++;
	return -gl_cost_of_opening_x;
}

